#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[105];
        scanf("%100s", s);
        int low = 0, high = 0;
        for (int i = 0; s[i]; ++i) {
            if (s[i] == '(') {
                low++; high++;
            } else if (s[i] == ')') {
                if (low > 0) low--;
                high--;
            } else { // '*'
                if (low > 0) low--;
                high++;
            }
            if (high < 0) break;
        }
        if (high >= 0 && low == 0) printf("true\n");
        else printf("false\n");
    }
    return 0;
}

