import sys

def is_valid(s: str) -> bool:
    low = high = 0
    for ch in s:
        if ch == '(':
            low += 1
            high += 1
        elif ch == ')':
            if low > 0:
                low -= 1
            high -= 1
        else:  # '*'
            if low > 0:
                low -= 1
            high += 1
        if high < 0:
            return False
    return low == 0

it = iter(sys.stdin.read().splitlines())
T = int(next(it))
out = []
for _ in range(T):
    s = next(it).strip()
    out.append('true' if is_valid(s) else 'false')
print('\n'.join(out))

